158→export function buildAnnotationTags(floor) {
159→  return applyCollisionOffsets([
160→    ...buildColumnTags(floor.columns || []),
161→    ...buildBeamTags(floor.beams || [], floor.columns || []),
162→    ...buildRoomTags(floor.rooms || []),
163→    ...buildDoorTags(floor.doors || [], floor.walls || []),
164→    ...buildWindowTags(floor.windows || [], floor.walls || []),
165→  ]);
166→}
