687→  const width = (maxLineLength * fontSize * 0.58) + Math.max(maskPaddingX, fontSize * 0.5);
688→  const height = Math.max(lineHeight, tag.textLines.length * lineHeight) + maskPaddingY;
689→  const minX = tag.textAnchor === 'start'
