691→    : (tag.textAnchor === 'end' ? tag.position.x - width : tag.position.x - (width / 2));
692→  const maxX = tag.textAnchor === 'start'
693→    ? tag.position.x + width
694→    : (tag.textAnchor === 'end' ? tag.position.x : tag.position.x + (width / 2));
