 76→function buildProfileFromStructuralOutline(metrics, structuralOutline, options = {}) {
 77→  const webMode = options.webMode || (metrics.family === 'gable' ? 'gable' : 'alternating');
 78→  const bottomPoints = createBottomPoints(metrics);
 79→  const topPoints = bottomPoints.map((point, index) => {
 80→    const sampled = sampleOutlineAtX(structuralOutline, point.x);
 81→    return {
 82→      x: point.x,
 83→      z: sampled.z,
 84→      kind: sampled.z >= Math.max(...structuralOutline.map((entry) => entry.z)) - EPSILON
 85→        ? (metrics.family === 'gable' ? 'ridge' : 'top_chord')
 86→        : 'top_chord',
 87→    };
 88→  });
 89→
 90→  const overhangPoints = [
 91→    { x: -metrics.overhangStart, z: structuralOutline[0]?.z || 0, kind: 'overhang' },
 92→    { x: metrics.span + metrics.overhangEnd, z: structuralOutline[structuralOutline.length - 1]?.z || 0, kind: 'overhang' },
 93→  ];
 94→
 95→  const topNodes = createLocalNodeMap(topPoints, 'top');
 96→  const bottomNodes = createLocalNodeMap(bottomPoints, 'bottom');
 97→  const overhangNodes = createLocalNodeMap(overhangPoints, 'overhang');
 98→  const members = [];
 99→
100→  addMember(members, overhangNodes[0].id, topNodes[0].id, 'topChord', members.length);
101→  for (let index = 0; index < topNodes.length - 1; index += 1) {
102→    addMember(members, topNodes[index].id, topNodes[index + 1].id, 'topChord', members.length);
103→  }
104→  addMember(members, topNodes[topNodes.length - 1].id, overhangNodes[1].id, 'topChord', members.length);
105→
106→  for (let index = 0; index < bottomNodes.length - 1; index += 1) {
107→    addMember(members, bottomNodes[index].id, bottomNodes[index + 1].id, 'bottomChord', members.length);
108→  }
109→
110→  for (let index = 1; index < bottomNodes.length - 1; index += 1) {
111→    if (Math.abs(topPoints[index].z - bottomPoints[index].z) <= EPSILON) continue;
112→    addMember(members, bottomNodes[index].id, topNodes[index].id, 'web', members.length);
113→  }
114→
115→  if (webMode === 'gable') {
116→    const midpoint = metrics.panelCount / 2;
117→    for (let index = 0; index < metrics.panelCount; index += 1) {
118→      if (index < midpoint) {
119→        addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
120→        continue;
121→      }
122→      addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
123→    }
124→  } else {
125→    for (let index = 0; index < metrics.panelCount; index += 1) {
126→      if (index % 2 === 0) {
127→        addMember(members, bottomNodes[index].id, topNodes[index + 1].id, 'web', members.length);
128→        continue;
129→      }
130→      addMember(members, topNodes[index].id, bottomNodes[index + 1].id, 'web', members.length);
131→    }
132→  }
133→
134→  return {
135→    nodes: [...overhangNodes, ...topNodes, ...bottomNodes],
136→    members,
137→    roofOutline: [
138→      { x: -metrics.overhangStart, z: structuralOutline[0]?.z || 0 },
139→      ...structuralOutline,
140→      { x: metrics.span + metrics.overhangEnd, z: structuralOutline[structuralOutline.length - 1]?.z || 0 },
141→    ],
142→    bottomOutline: bottomPoints,
143→    topChordRuns: options.topChordRuns || [{
