151→export function resolveTrussMetrics(instance, trussType = resolveTrussType(instance?.trussTypeId)) {
152→  const family = trussType.family;
153→  const shape = trussType.shape || family;
154→  const span = Math.max(Number(instance?.span || trussType.defaultSpan || 0), 1000);
155→  const run = family === 'gable' ? span / 2 : span;
156→  const defaultPitch = Number(trussType.defaultPitch || 0);
157→  const defaultRise = Number(trussType.defaultRise || 0);
158→  const explicitRise = Number(instance?.rise);
159→  const explicitPitch = Number(instance?.pitch);
160→
161→  if (shape === 'flat') {
162→    const rise = Number.isFinite(explicitRise) ? Math.max(0, explicitRise) : Math.max(0, defaultRise || 900);
163→    return {
164→      family,
165→      shape,
166→      span,
167→      rise,
168→      pitch: 0,
169→      overhangStart: Math.max(Number(instance?.overhangs?.start || 0), 0),
170→      overhangEnd: Math.max(Number(instance?.overhangs?.end || 0), 0),
171→      bearingStart: Number(instance?.bearingOffsets?.start || 0),
172→      bearingEnd: Number(instance?.bearingOffsets?.end || 0),
173→      panelCount: Math.max(2, Math.round(trussType.webPattern?.panelCount || 4)),
174→    };
175→  }
176→
177→  const riseFromPitch = ((Number.isFinite(explicitPitch) ? explicitPitch : defaultPitch) / 100) * Math.max(run, 1);
178→  const rise = Number.isFinite(explicitRise) ? Math.max(0, explicitRise) : Math.max(0, riseFromPitch || defaultRise);
179→  const pitch = Number.isFinite(explicitPitch)
180→    ? Math.max(0, explicitPitch)
181→    : ((rise / Math.max(run, 1)) * 100);
182→
183→  return {
184→    family,
185→    shape,
186→    span,
187→    rise,
188→    pitch,
189→    overhangStart: Math.max(Number(instance?.overhangs?.start || 0), 0),
190→    overhangEnd: Math.max(Number(instance?.overhangs?.end || 0), 0),
191→    bearingStart: Number(instance?.bearingOffsets?.start || 0),
192→    bearingEnd: Number(instance?.bearingOffsets?.end || 0),
193→    panelCount: Math.max(2, Math.round(trussType.webPattern?.panelCount || 4)),
194→  };
195→}
