472→  switch (shape) {
473→    case 'flat':
474→      profile = buildFlatProfile(metrics);
475→      break;
476→    case 'hip':
477→      profile = Number.isFinite(options?.layoutOffset) && Number.isFinite(options?.supportLength)
478→        ? buildHipSliceProfile(metrics, options)
479→        : buildHipProfile(metrics);
